var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래서…….","JPN":"で……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"받은 돈으로 먹을 건 하나도 안 사고 이 데이터패드 쪼가리만 샀다고?","JPN":"貰った金で食べ物は何も買わずにこのデータパッドだけ買ったのか？","ENG":"You didn't buy food with the money, but you bought this tiny data pad piece of junk?","TWN":"你沒有把換到的錢拿去買吃的，而是買了這塊破爛板子嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그야 당연하죠! 여기에 묻혀 있는 것들은 분명 이것보다 훨씬 가치 있다고요!","JPN":"当り前です！　ここに埋まっているのはきっとこれより遥かに価値のあるものなんです！","ENG":"Of course! Everything that's buried there is worth so much more than this data pad!","TWN":"必須買吧！這張藏寶圖裡的寶藏一定更有價值！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"애초에 그게 진짜 대해적의 보물지도인지, 아니면 그냥 굴러다니던 장물에 있지도 않은 스토리를 가져다 붙인 건지 어떻게 확신해?","JPN":"そもそも、それが本当に大海賊の宝の地図なのか、ただ転がっていた贓物で嘘をついたのか、どうやってわかるんだ？","ENG":"How are you sure that it's really the Great Pirate's treasure map? What if he just told you a made-up story to sell some junk?","TWN":"你怎麼知道這真的是大海盜的藏寶圖，還是只是大家對贓物的以訛傳訛？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그야 의심할 필요도 없죠!","JPN":"それは疑う余地もありませんよ！","ENG":"Well, there's no doubt about it!","TWN":"完全不需要懷疑！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"수염 기르는 해적 출신 아저씨들은 거짓말 같은 거 안 하거든요!","JPN":"ヒゲのある元海賊のおじさんは嘘なんかしないんです！","ENG":"Ex-pirates with beards never lie!","TWN":"留鬍子的前任海盜大叔是不會說謊的！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"진짜 입 꾹 닫고 있는 것보다 신뢰도가 떨어지는 변명인데?","JPN":"黙っているより信頼できない答えなんだが？","ENG":"That's even worse than saying nothing.","TWN":"這句話完全沒有任何可信度。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀哀…"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래도 남은 돈은 선장이 맡았으니, 이번에야 말로 제대로 된 음식을 사오겠지…","JPN":"でも残りの金は船長が持っているから、今度こそちゃんとした食べ物を買ってくるはず……","ENG":"At least the rest of the money is with Captain. She'll buy some proper food...","TWN":"至少剩下的錢在船長那裡，她應該會買些吃的回來吧…"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"샤크스 해적단! 좋은 소식이 있다!","JPN":"シャークス海賊団！　いい知らせがある！","ENG":"Hey, Sharks! I bring good news!","TWN":"大白鯊海盜團！有好消息！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"빈손인 걸 보니, 선장도 음식 안 사고 딴길로 샜구나?","JPN":"手ぶらなのを見ると、船長も食べ物を買わずに寄り道したな？","ENG":"Seeing as how you're empty-handed, I'm guessing you didn't buy food either.","TWN":"看船長兩手空空地回來，我想你也沒買吃的，而是買了其他東西吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫, 역시 내 선원들은 눈치가 빠르다니까.","JPN":"キャハハッ、さすがあたしの船員は気が利くね。","ENG":"Kya hah hah, aren't you a witty one!","TWN":"哈哈哈，我的船員果然都很聰明。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하아… 됐어.","JPN":"はあ……もういいよ。","ENG":"*Sigh...* Whatever.","TWN":"哀哀…算了。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그냥 먹을 건 내가 구해올 테니 돈이나 줘.","JPN":"食べ物はあたしが買ってくるから金をくれ。","ENG":"I'll get the food. Just give me the money.","TWN":"給我錢，我去買吃的東西回來吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"응? 한 푼도 안 남았는데?","JPN":"ん？　一つも残っていないけど？","ENG":"Hmm? I have no cash left.","TWN":"嗯？我全花光咧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장, 대체 뭘 산 거야?","JPN":"船長、いったい何を買ったんだ？","ENG":"Captain, what on earth did you buy?","TWN":"船長，你到底買了什麼？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"쓸 만한 배를 하나 구했지. 커다란 대포도 달려 있지롱.","JPN":"使えそうな船を一つ手に入れた。大きい大砲も付いてるよ。","ENG":"I got us a ship. It's got a big cannon too.","TWN":"我買了一艘不錯的船，上面還有內建大砲呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 돈을 전부 털어서 배를 샀다고?!","JPN":"その金を全部使って船を買ったって！？","ENG":"You used all that money to get a ship?!","TWN":"你把錢全拿去買船？！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"역시 선장! 돈 쓰는 법을 좀 아시네요!","JPN":"さすが船長！　お金の使い方をよくご存じですね！","ENG":"Ooh, Captain! That's what I'm talkin' about!","TWN":"不愧是船長！很懂得花錢！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};